3033 void VPlanTransforms::convertToAbstractRecipes(VPlan &Plan, VPCostContext &Ctx,
3034                                                VFRange &Range) {
3035   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
3036            vp_depth_first_deep(Plan.getVectorLoopRegion()))) {
3037     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
3038       if (auto *Red = dyn_cast<VPReductionRecipe>(&R))
3039         tryToCreateAbstractReductionRecipe(Red, Ctx, Range);
3040     }
3041   }
3042 }
