1301 void VPPhi::execute(VPTransformState &State) {
1302   State.setDebugLocFrom(getDebugLoc());
1303   PHINode *NewPhi = State.Builder.CreatePHI(
1304       State.TypeAnalysis.inferScalarType(this), 2, getName());
1305   unsigned NumIncoming = getNumIncoming();
1306   if (getParent() != getParent()->getPlan()->getScalarPreheader()) {
1307     // TODO: Fixup all incoming values of header phis once recipes defining them
1308     // are introduced.
1309     NumIncoming = 1;
1310   }
1311   for (unsigned Idx = 0; Idx != NumIncoming; ++Idx) {
1312     Value *IncV = State.get(getIncomingValue(Idx), VPLane(0));
1313     BasicBlock *PredBB = State.CFG.VPBB2IRBB.at(getIncomingBlock(Idx));
1314     NewPhi->addIncoming(IncV, PredBB);
1315   }
1316   State.set(this, NewPhi, VPLane(0));
1317 }
