 898     // first operand with an active lane and add the number of lanes of the
 899     // preceding operands.
 900     Value *RuntimeVF =
 901         getRuntimeVF(State.Builder, State.Builder.getInt64Ty(), State.VF);
 902     unsigned LastOpIdx = getNumOperands() - 1;
 903     Value *Res = nullptr;
 904     for (int Idx = LastOpIdx; Idx >= 0; --Idx) {
 905       Value *TrailingZeros = Builder.CreateCountTrailingZeroElems(
 906           Builder.getInt64Ty(), State.get(getOperand(Idx)), true, Name);
 907       Value *Current = Builder.CreateAdd(
 908           Builder.CreateMul(RuntimeVF, Builder.getInt64(Idx)), TrailingZeros);
