1008 bool VPInstruction::isVectorToScalar() const {
1009   return getOpcode() == VPInstruction::ExtractLastElement ||
1010          getOpcode() == VPInstruction::ExtractPenultimateElement ||
1011          getOpcode() == Instruction::ExtractElement ||
1012          getOpcode() == VPInstruction::ExtractLane ||
1013          getOpcode() == VPInstruction::FirstActiveLane ||
1014          getOpcode() == VPInstruction::ComputeAnyOfResult ||
1015          getOpcode() == VPInstruction::ComputeFindIVResult ||
1016          getOpcode() == VPInstruction::ComputeReductionResult ||
1017          getOpcode() == VPInstruction::AnyOf;
